// agent/tests/vault_consistency.rs

//! Vault Consistency: Final output validation.
//! Ensures that the JSON generated by Protocol 19 (Temporal Projectile)
//! strictly adheres to the schema expected by the Bridge and integration layers.

use chrono_seo_agent::protocols::{SeoSignal, temporal_projectile::TemporalProjectile};
use serde_json::Value;
use std::fs;

#[tokio::test]
async fn test_vault_schema_integrity() {
    // 1. Setup: Create a controlled signal set
    let signals = vec![
        SeoSignal {
            keyword: "Post-Quantum Cryptography".to_string(),
            momentum: 95.0,
            stability_score: Some(0.12),
        },
    ];

    // 2. Execution: Deploy to a test vault path
    // Note: In a real test environment, we would use a temporary file,
    // but here we validate the logic of Protocol 19's serialization.
    let _ = TemporalProjectile::deploy(signals).await;

    // 3. Validation: Read the generated vault
    let vault_content = fs::read_to_string("../vault/truth-vault.json")
        .expect("Consistency Error: Truth-Vault file not found after deployment.");

    let v: Value = serde_json::from_str(&vault_content)
        .expect("Consistency Error: Vault contains invalid JSON.");

    // 4. Schema Assertions
    // Check for mandatory Ark Metadata
    assert!(v.get("pulse_timestamp").is_some(), "Schema Violation: Missing pulse_timestamp");
    assert!(v.get("protocol_version").is_some(), "Schema Violation: Missing protocol_version");
    assert!(v.get("data").is_some(), "Schema Violation: Missing data array");

    // Check data integrity
    let data = v["data"].as_array().expect("Schema Violation: 'data' field is not an array");
    assert!(!data.is_empty(), "Consistency Error: Vault deployed with empty data");

    let first_signal = &data[0];
    assert!(first_signal.get("keyword").is_some(), "Schema Violation: Signal missing 'keyword'");
    assert!(first_signal.get("momentum").is_some(), "Schema Violation: Signal missing 'momentum'");
    assert!(first_signal.get("stability_score").is_some(), "Schema Violation: Signal missing 'stability_score'");
}

#[test]
fn test_vault_atomic_overwrite() {
    // This test ensures that the vault is overwritten, not appended to.
    // If the vault was 100KB, a new pulse of 1KB should result in a 1KB file.
    
    let path = "../vault/truth-vault.json";
    
    // Simulate a large previous vault
    let large_data = "X".repeat(1000); 
    fs::write(path, large_data).unwrap();

    // Run a small deployment logic (Mocked logic of TemporalProjectile)
    let small_data = r#"{"pulse": "test"}"#;
    fs::write(path, small_data).unwrap();

    let final_content = fs::read_to_string(path).unwrap();
    assert_eq!(final_content, small_data, "Consistency Error: Vault was not atomically overwritten.");
}
